  ($lum$636013ec-6f12-5525-9a65-56b64e8ceb3e$lum$::uuid, $lum$first-steps-module-check$lum$, $lum$module$lum$, NULL, $lum$29b588fb-3344-5efd-97f4-813d16bc9ea3$lum$::uuid, NULL, $lum$First steps: test out$lum$, $lum$Already get a real win in your first session, frame a request well, steer a draft, and paste safely? Pass this and the whole First Steps module leaves your path, marked complete.$lum$, 8, 0.8, 24, 'published')
